// GENERATED by behavior-contracts (bc#90, rust-typed-native — the RUNTIME-FREE read de-box; STRUCT-ONLY,
// FULLY-NATIVE). A covered read is a strictly-sequential typed componentRef chain (point reads +
// relationKind:single children), emitted ONLY as a STRUCT-returning runner that calls the op-agnostic leaf
// TRANSPORT symbol DIRECTLY at each covered node's execution point: native ports struct IN (direct
// construction — every port is a CONCRETE Rust value: String / bool / Vec<&str> projection / i64 limit —
// NO boxed Value, NO by-name accessor); the transport is called with the node's port fields spread and
// returns the node's result WIRE (a value implementing WireValue), and the runner de-boxes it INLINE
// (fully-unrolled probe/match — no decode helper, no output recursion) into the node's outType struct.
// There is NO per-node handler indirection — a leaf is ONE transport, not one method per authored node.
// The covered plane carries NO bc-runtime reference at all — failures use the LOCAL BehaviorError (same
// codes, byte-equal to run_behavior). INLINE sequential (no plan driver) so a relation child reads the
// parent's REAL struct result via direct field access and the child-present decision is made from the real
// parent value — relationSingle / connection converge with run_behavior (fixes #323/#74). The exposed API
// is run_native_raw_struct_<comp>(in_) over the CONCRETE InNR_<comp> input struct; the consumer supplies
// the leaf transport symbols (default in-scope names leaf_<comp>, or a leafTransport import). This module
// is FULLY NATIVE: a naive grep for boxing primitives OR for the bc-runtime crate finds nothing, by design.
use std::cell::RefCell;

// #165 --shared-types-import: the BC-OWNED wire seam lives in the shared crate/module — import it.
use litedbmodel_runtime::*;

// De-box / op-failure constructors (produce the shared BehaviorError, imported above). Runtime-free.
// op_failed — wrap a leaf failure as the node's Failure under its Error Policy Kind, carrying the
// leaf's structured detail through unchanged (the runner transports the Error Value; it does not
// synthesize or re-interpret it).
#[allow(dead_code)]
fn op_failed(node: &str, policy: &str, e: BehaviorError) -> BehaviorError {
    BehaviorError {
        code: "OP_FAILED".to_string(),
        message: format!("operation '{node}' failed under '{policy}' policy: {}", e.message),
        detail: e.detail,
    }
}

// de_type_mismatch / de_missing_field / de_overflow — the de-box mismatch failures the generated decode
// produces (scp-error.md "The Error Value"). Codes are byte-equal to the runtime outType check
// (TYPE_MISMATCH / MISSING_PROP) so the covered read stays equivalent to run_behavior; detail.kind
// distinguishes typeMismatch / missingField / overflow.
#[allow(dead_code)]
fn de_type_mismatch(model: &str, field: &str, expected: &str, actual_wire: String, raw: String) -> BehaviorError {
    BehaviorError::with_detail(
        "TYPE_MISMATCH",
        format!("node '{model}': {field}: expected {expected}, got {actual_wire}"),
        ErrorDetail {
            kind: Some(ErrorKind::TypeMismatch),
            model: Some(model.to_string()),
            field: Some(field.to_string()),
            expected_type: Some(expected.to_string()),
            actual_wire_type: Some(actual_wire),
            raw_value: Some(raw),
            context: std::collections::BTreeMap::new(),
        },
    )
}

#[allow(dead_code)]
fn de_missing_field(model: &str, field: &str, expected: &str) -> BehaviorError {
    BehaviorError::with_detail(
        "MISSING_PROP",
        format!("node '{model}': {field}: required field is absent"),
        ErrorDetail {
            kind: Some(ErrorKind::MissingField),
            model: Some(model.to_string()),
            field: Some(field.to_string()),
            expected_type: Some(expected.to_string()),
            actual_wire_type: None,
            raw_value: None,
            context: std::collections::BTreeMap::new(),
        },
    )
}

#[allow(dead_code)]
fn de_overflow(model: &str, field: &str, expected: &str, actual_wire: String, raw: String) -> BehaviorError {
    let message = format!("node '{model}': {field}: {raw} is outside the range of {expected}");
    BehaviorError::with_detail(
        "TYPE_MISMATCH",
        message,
        ErrorDetail {
            kind: Some(ErrorKind::Overflow),
            model: Some(model.to_string()),
            field: Some(field.to_string()),
            expected_type: Some(expected.to_string()),
            actual_wire_type: Some(actual_wire),
            raw_value: Some(raw),
            context: std::collections::BTreeMap::new(),
        },
    )
}

